// Package mcp is the runtime support library for MCP proxy
// binaries generated by the wandering-compiler gateway domain
// (G3i3-GW-MCP). Adapted from protobridge's `runtime/mcp`
// package per the conventions doc that points at protobridge
// as the reference runtime.
//
// The generated MCP proxy emits a thin main.go + per-service
// handler files that register tools against this package; all
// wire concerns (transport, auth, gRPC dispatch) live here.
package mcp

import (
	"context"
	"net/http"
	"os"
	"strings"

	"google.golang.org/grpc/metadata"
)

// ConnectionInfo gives an MCPAuthFunc a unified view of the
// originating connection regardless of transport. Each field
// is populated when the runtime can extract that source for
// the current request:
//
//   - Env: explicit map for tests; the DefaultAuthFunc falls
//     back to os.Getenv when the map is nil/empty.
//   - HTTPHeaders: populated by ServeStreamableHTTP for
//     inbound HTTP requests via the unexported context key.
//     Always nil in stdio mode.
//   - InitializeParams: reserved for the MCP `initialize`
//     handshake's params object. Not yet populated; left in
//     the struct so the MCPAuthFunc signature stays stable
//     when the wiring lands.
type ConnectionInfo struct {
	Env              map[string]string
	HTTPHeaders      http.Header
	InitializeParams map[string]any
}

// MCPAuthFunc translates a per-connection identity (env vars,
// HTTP headers, MCP initialize params) into gRPC metadata that
// the proxy attaches to every backend call. Returning an error
// fails the MCP request.
//
// Implementations should be cheap — they may run on every
// tool call when using HTTP transport without session
// persistence.
type MCPAuthFunc func(ctx context.Context, conn ConnectionInfo) (metadata.MD, error)

// DefaultAuthFunc forwards a configurable list of identity
// keys from env vars and HTTP headers into gRPC metadata,
// lowercasing keys per the gRPC convention. Wrap it for
// projects that need DB lookups or token validation.
//
// Each key in `forward` is checked against (in order):
//  1. ConnectionInfo.HTTPHeaders[key]            (HTTP transport)
//  2. ConnectionInfo.InitializeParams[lowercase] (MCP initialize handshake)
//  3. ConnectionInfo.Env[snake-uppercase form]   (stdio transport)
//
// Example: forward=["session_id"] with the env var
// `SESSION_ID=abc` set produces metadata `session_id=abc`.
func DefaultAuthFunc(forward ...string) MCPAuthFunc {
	return func(_ context.Context, conn ConnectionInfo) (metadata.MD, error) {
		md := metadata.MD{}
		for _, key := range forward {
			if v := lookup(conn, key); v != "" {
				md.Set(strings.ToLower(key), v)
			}
		}
		return md, nil
	}
}

func lookup(conn ConnectionInfo, key string) string {
	if conn.HTTPHeaders != nil {
		if v := conn.HTTPHeaders.Get(key); v != "" {
			return v
		}
	}
	if conn.InitializeParams != nil {
		if v, ok := conn.InitializeParams[strings.ToLower(key)].(string); ok && v != "" {
			return v
		}
	}
	if conn.Env != nil {
		if v := conn.Env[envKey(key)]; v != "" {
			return v
		}
	}
	// Fallback to process env so generated main.go doesn't
	// have to read os.Environ() itself.
	return os.Getenv(envKey(key))
}

// CollectAuthHeaders flattens every identity source a ConnectionInfo
// carries into one lowercased header map for forwarding to the backend
// auth service. It is the BULK counterpart to lookup(): the generated MCP
// authFn / permResolver forward every identity header (not a fixed key
// list), so they call this instead of reading only ConnectionInfo.HTTPHeaders
// — which is nil on the stdio transport (Q63-mcp-1), silently breaking
// authentication there.
//
// Sources merge in increasing precedence (later wins):
//
//  1. Env             — stdio: the prefix-scoped process environment,
//     SCREAMING_SNAKE-keyed (matching envKey), reversed to header form.
//  2. InitializeParams — the MCP `initialize` handshake (string values).
//  3. HTTPHeaders     — HTTP transport (canonical, highest precedence).
//
// Only the maps actually present on the ConnectionInfo contribute — it
// never reads os.Environ itself, so an unscoped process environment is
// never bulk-forwarded (the env snapshot is scoped to the server's auth
// prefix by SetAuthEnvPrefix).
func CollectAuthHeaders(conn ConnectionInfo) map[string]string {
	out := map[string]string{}
	for k, v := range conn.Env {
		if v != "" {
			out[headerFromEnvKey(k)] = v
		}
	}
	for k, v := range conn.InitializeParams {
		if s, ok := v.(string); ok && s != "" {
			out[strings.ToLower(k)] = s
		}
	}
	for k, vs := range conn.HTTPHeaders {
		if len(vs) > 0 {
			out[strings.ToLower(k)] = vs[0]
		}
	}
	return out
}

// headerFromEnvKey reverses envKey: a SCREAMING_SNAKE env key maps back to
// the lowercased HTTP-style header name the backend auth service sees from
// the HTTP transport (e.g. "AUTHORIZATION" → "authorization",
// "X_API_KEY" → "x-api-key").
func headerFromEnvKey(k string) string {
	return strings.ToLower(strings.ReplaceAll(k, "_", "-"))
}

// envKey converts a metadata-style key (e.g. "session_id")
// to the SCREAMING_SNAKE form most parents use for env vars
// (e.g. "SESSION_ID").
func envKey(key string) string {
	out := make([]byte, 0, len(key))
	for i := 0; i < len(key); i++ {
		c := key[i]
		switch {
		case c >= 'a' && c <= 'z':
			out = append(out, c-32)
		case c == '-':
			out = append(out, '_')
		default:
			out = append(out, c)
		}
	}
	return string(out)
}
